import React from "react";

function Stars({ value }) {
  const full = Math.round(value);
  return (
    <div>
      {"★★★★★".slice(0, full)}
      {"☆☆☆☆☆".slice(full)}
      <span style={{ marginLeft: 6 }}>{value}</span>
    </div>
  );
}

function CourseCard({ course }) {
  return (
    <div style={styles.card}>
      <img
        src={course.image || "https://picsum.photos/300/160"}
        alt={course.title}
        style={styles.img}
      />

      <h3>{course.title}</h3>
      <p style={{ color: "#555" }}>{course.description}</p>

      <Stars value={course.rating || 0} />

      <a href={course.url} target="_blank" rel="noreferrer">
        Перейти к курсу
      </a>
    </div>
  );
}

const styles = {
  card: {
    width: 260,
    background: "#fff",
    borderRadius: 8,
    padding: 15,
    boxShadow: "0 3px 10px rgba(0,0,0,0.1)"
  },
  img: {
    width: "100%",
    borderRadius: 6,
    marginBottom: 10
  }
};

export default CourseCard;
